PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX foaf: <http://xmlns.com/foaf/0.1/>

SELECT ?id ?name WHERE {
  ?hw a pv:Hardware .
  FILTER NOT EXISTS {
    ?hw pv:hasProductManager ?pm .
    {
      ?pm a pv:ActiveManager
    } UNION {
      ?pm pv:status ?st .
      FILTER(lcase(str(?st)) = "active")
    }
  }

  OPTIONAL { ?hw rdfs:label ?lbl1 . }
  OPTIONAL { ?hw foaf:name ?lbl2 . }
  BIND(COALESCE(?lbl1, ?lbl2) AS ?name)

  BIND(REPLACE(STR(?hw), "^.*/", "") AS ?id)
}

