PREFIX pv: <http://ld.company.org/prod-vocab/>

SELECT ?id ?name ?width
WHERE {
  { # get min-max range
    SELECT (MIN(?width) AS ?minW) (MAX(?width) AS ?maxW)
    WHERE {
      ?hw a pv:Hardware ;
        pv:width_mm ?width .
    }
  }

  # get 90. percentile
  BIND(?minW + (0.9 * (?maxW - ?minW)) AS ?pct90)

  ?hw a pv:Hardware ;
    pv:id ?id ;
    pv:name ?name ;
    pv:width_mm ?width .

  FILTER(?width >= ?pct90)
}
ORDER BY DESC(?width)

